// Extract eval data from webhook body
const body = $input.first().json.body || $input.first().json;
const eval_data = body;
const date = eval_data.eval_date || new Date().toISOString().split('T')[0];
const company = (eval_data.company || 'unknown').toLowerCase().replace(/[^a-z0-9]+/g, '-');

// Generate sequential report number (use timestamp as fallback)
const num = eval_data.num || String(Date.now()).slice(-3).padStart(3, '0');
const filename = `${num}-${company}-${date}.md`;

return [{ json: { ...eval_data, report_filename: filename, report_num: num, report_date: date } }];

